// Invalid states get typed as `never`, causing compile errors.
interface Builder<State extends BuilderState> {
  setName: State extends 'Initial' ? (name: string) => Builder<'NameSet'> : never;
  setAge: State extends 'NameSet' ? (age: number) => Builder<'AgeSet'> : never;
